// --- VARIABLES ---
const data = $input.all()
const count = {
  "latin": 0,
  "general": 0,
  "european": 0,
  "asian": 0,
  "foreignladies": 0,
}
const draft = []
const defaultLimit = 15
const regionLimits = {
  "latin": 30,
}

// --- FUNCTIONS ---
function getFirstName(name) {
 if (name) {
   const parts = name.trim().split(/\s+/)
   return parts [0]
 } 
  return ""
}

function monthYearExtractor(timestamp) {
  if (!timestamp) return "";

  // 1. Get the date part (handle both space and 'T' separators)
  // 2. Normalize dashes to slashes
  const datePart = timestamp.split(/[T ]/)[0].replace(/-/g, '/');

  // 3. Remove the middle section (the day)
  // This looks for: slash -> digits -> slash AND replaces with: slash
  return datePart.replace(/\/\d{1,2}\//, '/');
}

function regionSelector(region, currentRegionCount) {
  if (region == 'latin') {
    // Alternates based on whether the count is even or odd
    return (currentRegionCount % 2 === 0) ? "First Latin Name" : "Second Latin Name";
  }
  if (region == 'asian') return "Corazon Dela Cruz"
  if (region == 'general') return "Maria Wilson"
  if (region == 'european') return "Anya Volkova"
  if (region == 'foreignladies') return "Amelia Johansson"
}

// --- MAIN ---
for (const item of data) {
  const region = String(item.json.region).trim().toLowerCase()
  const isDuplicate = item.json.is_duplicate
  const draftDate = item.json.draft_date
  const leadEmail = item.json.lead_email
  const leadName = item.json.lead_name
  const FBGroup = item.json.facebook_group
  const leadSource = item.json.lead_source
  const remarks = item.json.remarks
  const website = item.json.website
  const rowNumber = item.json.row_number
  const isResponded = item.json.is_responded
  const uid = item.json.uid
  // Splits at EITHER a 'T' or a space
  const timestamp = item.json.timestamp;

  if (isDuplicate || draftDate != "") {
    continue
  }

  if (isResponded) {
    continue
  }

  const currentLimit = regionLimits[region] || defaultLimit;

  if (region in count && monthYearExtractor(timestamp) === "12/2025" && count[region] < currentLimit){
    console.log(monthYearExtractor(timestamp))
    draft.push({
      json: {
        email: item.json.lead_email,
        agentName: regionSelector(region, count[region]),
        firstName: getFirstName(leadName),
        leadName: leadName,
        FBGroup: FBGroup,
        leadSource: leadSource,
        leadEmail: leadEmail,
        remarks: remarks,
        region: region,
        url: website,
        row: rowNumber,
        uid: uid,
        timestamp: timestamp
      }
    })
    count[region] += 1
  }
}

// --- RETURN ---
return draft

const PET = $("get rows in email tracker").all()
const db = $input.all()

// 1. Create a Set of all emails in the database for O(1) lookup speed
const existingEmails = new Set(
  db.map(e => e.json.to_email_address).filter(Boolean)
);

// 2. Filter the PET list and map to the desired output format
return PET
  .filter(item => {
    const email = item.json.lead_email;
    return email != null && !existingEmails.has(email);
  })        
  .map(item => ({ email: item }));

